  ALLOWED_FORMATS = %w[png jpg jpeg gif bmp tiff webp].freeze

  def convert
    uploaded_file = params[:image]
    target_format = params[:format]
    width = params[:width]
    height = params[:height]

    # Validate uploaded file is present
    unless uploaded_file.is_a?(ActionDispatch::Http::UploadedFile)
      return render json: { error: "No valid image file uploaded" }, status: :unprocessable_entity
    end

    # Validate and sanitize format (whitelist approach)
    sanitized_format = sanitize_format(target_format)
    unless sanitized_format
      return render json: { error: "Invalid format. Allowed formats: #{ALLOWED_FORMATS.join(', ')}" }, status: :unprocessable_entity
    end

    # Validate and sanitize dimensions
    sanitized_width = sanitize_dimension(width)
    sanitized_height = sanitize_dimension(height)

    unless sanitized_width && sanitized_height
      return render json: { error: "Invalid dimensions. Must be positive integers up to #{MAX_WIDTH}x#{MAX_HEIGHT}." }, status: :unprocessable_entity
    end

    # Validate the uploaded file content type
    unless uploaded_file.content_type&.start_with?("image/")
      return render json: { error: "Uploaded file is not a valid image" }, status: :unprocessable_entity
    end

