    input_path = save_to_tempfile(uploaded_file)
    unless input_path
      return render json: { error: "Failed to process uploaded file" }, status: :internal_server_error
    end

    output_path = Rails.root.join("tmp", "#{SecureRandom.uuid}.#{sanitized_format}").to_s

