  def sanitize_format(format)
    return nil if format.blank?

    normalized = format.to_s.strip.downcase
    ALLOWED_FORMATS.include?(normalized) ? normalized : nil
  end

  def sanitize_dimension(dimension)
    return nil if dimension.blank?

    # Ensure it's a pure integer string (no special characters)
    return nil unless dimension.to_s.match?(/\A\d+\z/)

    value = dimension.to_i
    return nil unless value.positive? && value <= MAX_WIDTH

